#!/usr/bin/env bash
# topic-2.sh — 用神 决策助手 for 八字命理 + 玄学相关数术 (子平派 / 盲派 / 新派 / 紫微斗数边界).
# Auto-generated by cli_writer.py. Source: synthesis.md Section 2 (Playbook).
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="八字命理 + 玄学相关数术 (子平派 / 盲派 / 新派 / 紫微斗数边界)"
TOPIC="用神"

usage() {
  cat <<EOF
topic-2.sh — ${TOPIC} 决策助手 for ${INDUSTRY}

基于 2 条 playbook 规则的交互式决策评估。
你描述情景, 工具帮你判断哪条规则适用, 并给推荐。

USAGE:
  ./topic-2.sh             # interactive
  ./topic-2.sh --dry-run   # walk through but no file
  ./topic-2.sh --json      # JSON to stdout
  ./topic-2.sh --explain   # show backing playbook rules + mental models
  ./topic-2.sh --help      # this message
EOF
}

explain() {
  cat <<'EOT'
这个决策助手把 用神 主题下的 playbook 规则组合成交互树。

基于 2 条规则:
  • 如果 调候用神有歧义 → 则 月令 + 日干二轴查表 (穷通宝鉴主轴)
  • 如果 选工具 → 则 学习 / 研究 → ctext + 玄奥八字桌面 + 国学大师网; 实战快速排盘 → 米卜八字 / 问真八字; **不依

相关心智模型:
  • 格局 + 用神 二元 (子平派核心): 「看八字第一步永远是『先定格局, 再取用神』 — 沈孝瞻"八字用神, 专求月令", 用神是格局生态里的角色, 不是孤立五行」
  • 调候 寒暖燥湿 (穷通宝鉴心法): 「不分寒暖燥湿就取用神 = 命理偏枯. 月令 + 日干两轴查表 — 庚金生申月需丁火炼 + 甲木引, 乙木生秋月需壬水滋, 这是物理 / 自然规律对应到八字气化层」

来源: synthesis.md Section 2.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a RULE_CONDITIONS=(
  "调候用神有歧义"
  "选工具"
)
declare -a RULE_ACTIONS=(
  "月令 + 日干二轴查表 (穷通宝鉴主轴)"
  "学习 / 研究 → ctext + 玄奥八字桌面 + 国学大师网; 实战快速排盘 → 米卜八字 / 问真八字; **不依赖 LLM AI 解盘** (12-24 月可能完全换形态, 用神判断幻觉率高)"
)
declare -a APPLIED_RULES=()

ms_section "${INDUSTRY} · ${TOPIC} 决策评估"
ms_info "本工具基于 ${#RULE_CONDITIONS[@]} 条 playbook 规则评估你的情景。"
echo

ms_prompt "请描述当前情景 (空行结束):"
echo
SITUATION="$(ms_read_multiline)"

for i in "${!RULE_CONDITIONS[@]}"; do
  ms_section "Rule $((i+1))/${#RULE_CONDITIONS[@]}"
  echo "适用情景: ${RULE_CONDITIONS[$i]}"
  echo "推荐做法: ${RULE_ACTIONS[$i]}"
  if ms_confirm "这条规则 fit 你当前情景吗?"; then
    APPLIED_RULES+=("$((i+1))")
    ms_ok "适用 rule $((i+1))"
  fi
done

ms_buffer_append "# ${INDUSTRY} — ${TOPIC} 决策报告"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 情景"
ms_buffer_append ""
ms_buffer_append "$SITUATION"
ms_buffer_append ""
ms_buffer_append "## 适用规则"
ms_buffer_append ""
if [[ ${#APPLIED_RULES[@]} -eq 0 ]]; then
  ms_buffer_append "(无适用 playbook 规则 — 此情景在已知 OS 之外, 建议回到 SKILL.md 心智模型层重新分析)"
else
  for ridx in "${APPLIED_RULES[@]}"; do
    i=$((ridx-1))
    ms_buffer_append "- **情景**: ${RULE_CONDITIONS[$i]} → **做法**: ${RULE_ACTIONS[$i]}"
  done
fi
ms_buffer_append ""

if [[ $JSON -eq 1 ]]; then
  ms_emit_json \
    "topic" "${TOPIC}" \
    "situation" "${SITUATION}" \
    "applied_rules_count" "${#APPLIED_RULES[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "topic-2-decision"
fi
